import atexit
import base64
import pathlib
import sys
import tempfile

EMBEDDED_SOURCES = {'cockpit_lifecycle_control.py': '', 'cockpit_lifecycle_websocket.py': '', 'cockpit_tmux_commands.py': '', 'cockpit_tmux_lifecycle.py': '', 'pseudoterminal_streams.py': '', 'server.py': '', 'settings.py': '', 'stdlib_websocket_server/__init__.py': '', 'stdlib_websocket_server/connection.py': '', 'stdlib_websocket_server/frame_protocol.py': '', 'stdlib_websocket_server/handshake.py': '', 'stdlib_websocket_server/listening_server.py': '', 'stdlib_websocket_server/request.py': '', 'stdlib_websocket_server/response.py': '', 'launcher.py': '', 'localhost_cockpit_entry.py': '', 'localhost_cockpit_index_html.py': '', 'localhost_cockpit_index_page_behavior_script.py': '', 'localhost_cockpit_index_page_layout.py': '', 'local_cockpit_assets.py': '', 'websockets/__init__.py': '', 'websockets/exceptions.py': 'ZnJvbSBzdGRsaWJfd2Vic29ja2V0X3NlcnZlciBpbXBvcnQgQ29ubmVjdGlvbkNsb3NlZAo='}


def materialize_embedded_sources_into_temporary_directory():
    extraction_directory = tempfile.TemporaryDirectory(prefix='local-cockpit-')
    extraction_root = pathlib.Path(extraction_directory.name)
    for relative_posix_path, encoded_source in EMBEDDED_SOURCES.items():
        destination_path = extraction_root / relative_posix_path
        destination_path.parent.mkdir(parents=True, exist_ok=True)
        destination_path.write_bytes(base64.b64decode(encoded_source))
    return extraction_directory


def run_bundled_localhost_cockpit_entry():
    extraction_directory = materialize_embedded_sources_into_temporary_directory()
    atexit.register(extraction_directory.cleanup)
    sys.path.insert(0, extraction_directory.name)
    import localhost_cockpit_entry
    localhost_cockpit_entry.main()


if __name__ == '__main__':
    run_bundled_localhost_cockpit_entry()
